let ImageSys, InPutButton, SendButton, FileInput, RotateButton, CropButton, UploadStatus;
let RefreshStatusButton, DeviceStatusPanel;
let modeButtons, tips;
let currentMode = 'AP';
let rotateAngle = 0;
let processedBase64 = "";
let fileFlag = 0;
let cropMode = "cover";

const palette = [
    [0, 0, 0],
    [255, 255, 255],
    [255, 255, 0],
    [255, 0, 0],
    null,
    [0, 0, 255],
    [0, 255, 0]
];

function setStatus(message, isError = false) {
    if (!UploadStatus) return;
    UploadStatus.textContent = message;
    const row = UploadStatus.closest('.status-row');
    if (row) {
        row.style.color = isError ? '#7b1d1d' : '';
        row.style.background = isError ? '#f8e4e4' : '';
    }
}

function setSendBusy(isBusy) {
    if (!SendButton) return;
    SendButton.disabled = isBusy;
    SendButton.textContent = isBusy ? 'Отправка...' : 'Отправить на рамку';
}

function setText(id, value) {
    const el = document.getElementById(id);
    if (el) el.textContent = value;
}

function getPowerText(battery) {
    if (!battery || !battery.available) return 'Батарея не обнаружена';
    if (battery.charging) return `Заряжается${battery.voltage_mv ? `, ${battery.voltage_mv} мВ` : ''}`;
    if (battery.discharging) return `Работает от батареи${battery.voltage_mv ? `, ${battery.voltage_mv} мВ` : ''}`;
    if (battery.vbus_good) return `Питание по USB${battery.voltage_mv ? `, ${battery.voltage_mv} мВ` : ''}`;
    return battery.charge_status ? battery.charge_status : 'Состояние питания неизвестно';
}

function renderDeviceStatus(data) {
    const battery = data.battery || {};
    const level = Number.isFinite(battery.level) ? battery.level : -1;
    const batteryFill = document.getElementById('battery_fill');

    if (battery.available && level >= 0) {
        setText('metric_battery', `${level}%`);
        if (batteryFill) {
            batteryFill.style.width = `${Math.max(0, Math.min(100, level))}%`;
            batteryFill.style.backgroundColor = level < 20 && battery.discharging ? '#b9362e' : '';
        }
    } else {
        setText('metric_battery', 'Нет данных');
        if (batteryFill) batteryFill.style.width = '0%';
    }
    setText('metric_power', getPowerText(battery));

    const network = data.network || {};
    const serverMode = network.mode === 'STA' ? 'STA' : 'AP';
    setText('metric_network', serverMode);
    setText('metric_address', serverMode === 'STA' ? 'Домашняя Wi-Fi сеть' : 'Точка доступа рамки');
    updateModeByValue(serverMode);
}

function loadDeviceStatus(showInlineError = false) {
    if (window.location.protocol === 'file:') {
        setText('metric_battery', 'Локальный файл');
        setText('metric_power', 'Состояние доступно только со страницы рамки');
        setText('metric_network', 'Недоступно');
        setText('metric_address', 'Откройте страницу с рамки');
        if (showInlineError) {
            setStatus('Откройте страницу с рамки, например http://192.168.4.1/index.html.', true);
        }
        return Promise.resolve();
    }
    if (RefreshStatusButton) RefreshStatusButton.disabled = true;
    return fetch('/DeviceStatus', { cache: 'no-store' })
        .then(response => {
            if (!response.ok) {
                throw new Error(`Request failed, status code:${response.status}`);
            }
            return response.json();
        })
        .then(renderDeviceStatus)
        .catch(error => {
            console.error('Не удалось получить состояние рамки:', error);
            setText('metric_battery', 'Недоступно');
            setText('metric_power', 'Прошивка без /DeviceStatus или нет связи');
            setText('metric_network', 'Недоступно');
            setText('metric_address', 'Проверьте подключение');
            if (showInlineError) {
                setStatus('Не удалось получить состояние рамки. Проверьте связь или обновите прошивку.', true);
            }
        })
        .finally(() => {
            if (RefreshStatusButton) RefreshStatusButton.disabled = false;
        });
}

function updateCropButton() {
    if (!CropButton) return;
    CropButton.textContent = cropMode === "cover" ? "Обрезка: вкл" : "Вписать целиком";
}

function getTargetSize(img) {
    if (img.naturalWidth > img.naturalHeight) {
        return { width: 800, height: 480 };
    }
    return { width: 480, height: 800 };
}

function drawPreparedImage(ctx, img, targetW, targetH) {
    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, targetW, targetH);

    const sourceRatio = img.naturalWidth / img.naturalHeight;
    const targetRatio = targetW / targetH;

    if (cropMode === "cover") {
        let sourceX = 0;
        let sourceY = 0;
        let sourceW = img.naturalWidth;
        let sourceH = img.naturalHeight;

        if (sourceRatio > targetRatio) {
            sourceW = img.naturalHeight * targetRatio;
            sourceX = (img.naturalWidth - sourceW) / 2;
        } else {
            sourceH = img.naturalWidth / targetRatio;
            sourceY = (img.naturalHeight - sourceH) / 2;
        }

        ctx.drawImage(img, sourceX, sourceY, sourceW, sourceH, 0, 0, targetW, targetH);
        return;
    }

    const scale = Math.min(targetW / img.naturalWidth, targetH / img.naturalHeight);
    const drawW = img.naturalWidth * scale;
    const drawH = img.naturalHeight * scale;
    const drawX = (targetW - drawW) / 2;
    const drawY = (targetH - drawH) / 2;
    ctx.drawImage(img, drawX, drawY, drawW, drawH);
}

function findNearestColorIndex(r, g, b) {
    let minDist = Infinity;
    let nearestIdx = 0;
    for (let i = 0; i < palette.length; i++) {
        if (palette[i] === null) continue;
        const pr = palette[i][0];
        const pg = palette[i][1];
        const pb = palette[i][2];
        const dist = (r - pr) ** 2 + (g - pg) ** 2 + (b - pb) ** 2;
        if (dist < minDist) {
            minDist = dist;
            nearestIdx = i;
        }
    }
    return nearestIdx;
}

function ditherCanvas(canvas, ctx) {
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    const idxArr = new Uint8Array(canvas.width * canvas.height);

    for (let y = 0; y < canvas.height; y++) {
        for (let x = 0; x < canvas.width; x++) {
            const i = (y * canvas.width + x) * 4;
            const oldR = data[i];
            const oldG = data[i + 1];
            const oldB = data[i + 2];
            const idx = findNearestColorIndex(oldR, oldG, oldB);
            const [newR, newG, newB] = palette[idx];

            data[i] = newR;
            data[i + 1] = newG;
            data[i + 2] = newB;
            idxArr[y * canvas.width + x] = idx;

            const errR = oldR - newR;
            const errG = oldG - newG;
            const errB = oldB - newB;

            if (x + 1 < canvas.width) {
                let j = i + 4;
                data[j] = Math.max(0, Math.min(255, data[j] + errR * 7 / 16));
                data[j + 1] = Math.max(0, Math.min(255, data[j + 1] + errG * 7 / 16));
                data[j + 2] = Math.max(0, Math.min(255, data[j + 2] + errB * 7 / 16));
            }
            if (x > 0 && y + 1 < canvas.height) {
                let j = i + (canvas.width - 1) * 4;
                data[j] = Math.max(0, Math.min(255, data[j] + errR * 3 / 16));
                data[j + 1] = Math.max(0, Math.min(255, data[j + 1] + errG * 3 / 16));
                data[j + 2] = Math.max(0, Math.min(255, data[j + 2] + errB * 3 / 16));
            }
            if (y + 1 < canvas.height) {
                let j = i + canvas.width * 4;
                data[j] = Math.max(0, Math.min(255, data[j] + errR * 5 / 16));
                data[j + 1] = Math.max(0, Math.min(255, data[j + 1] + errG * 5 / 16));
                data[j + 2] = Math.max(0, Math.min(255, data[j + 2] + errB * 5 / 16));
            }
            if (x + 1 < canvas.width && y + 1 < canvas.height) {
                let j = i + (canvas.width + 1) * 4;
                data[j] = Math.max(0, Math.min(255, data[j] + errR * 1 / 16));
                data[j + 1] = Math.max(0, Math.min(255, data[j + 1] + errG * 1 / 16));
                data[j + 2] = Math.max(0, Math.min(255, data[j + 2] + errB * 1 / 16));
            }
        }
    }

    ctx.putImageData(imageData, 0, 0);
    window._lastImageIndexArray = idxArr;
}

function renderProcessedPreview() {
    const processedImg = document.getElementById('Image_Processed');
    if (!processedImg || !processedBase64) return;

    const img = new window.Image();
    img.onload = function () {
        let w = img.naturalWidth;
        let h = img.naturalHeight;
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');

        if (rotateAngle % 180 === 0) {
            canvas.width = w;
            canvas.height = h;
        } else {
            canvas.width = h;
            canvas.height = w;
        }

        ctx.save();
        ctx.translate(canvas.width / 2, canvas.height / 2);
        ctx.rotate((rotateAngle % 360) * Math.PI / 180);
        ctx.drawImage(img, -w / 2, -h / 2);
        ctx.restore();
        processedImg.src = canvas.toDataURL();
    };
    img.src = processedBase64;
}

function processCurrentImage() {
    if (!ImageSys || !ImageSys.complete || !ImageSys.naturalWidth) return;

    const { width: targetW, height: targetH } = getTargetSize(ImageSys);
    const canvas = document.createElement('canvas');
    canvas.width = targetW;
    canvas.height = targetH;
    const ctx = canvas.getContext('2d');

    drawPreparedImage(ctx, ImageSys, targetW, targetH);
    ditherCanvas(canvas, ctx);

    processedBase64 = canvas.toDataURL();
    renderProcessedPreview();

    const cropText = cropMode === "cover" ? "с центрированной обрезкой" : "с белыми полями";
    setStatus(`Изображение подготовлено ${cropText}: ${canvas.width}x${canvas.height}. Можно отправлять.`);
}

function updateModeByValue(targetMode) {
    const validModes = ['AP', 'STA'];
    if (!validModes.includes(targetMode)) {
        console.warn('Invalid mode value. Using default AP mode.');
        targetMode = 'AP';
    }

    const activeButton = document.querySelector(`a[data-mode="${targetMode}"]`);
    if (activeButton) {
        modeButtons.forEach(btn => btn.classList.remove('active'));
        activeButton.classList.add('active');
        currentMode = targetMode;
        updateTips();
    }
}

function initializeMode() {
    updateModeByValue('AP');
}

function updateTips() {
    tips.forEach(tip => tip.classList.remove('d-none'));
    if (currentMode === "AP") {
        document.getElementById('tips-STA')?.classList.add('d-none');
    } else {
        document.getElementById('tips-AP')?.classList.add('d-none');
    }
}

function Even_init() {
    InPutButton = document.getElementById("Input_Button");
    SendButton = document.getElementById("Send_Button");
    FileInput = document.getElementById("File_Input");
    ImageSys = document.getElementById("Image_Input");
    RotateButton = document.getElementById("Rotate_Button");
    CropButton = document.getElementById("Crop_Button");
    RefreshStatusButton = document.getElementById("Refresh_Status_Button");
    DeviceStatusPanel = document.getElementById("Device_Status_Panel");
    UploadStatus = document.getElementById("upload_status");
    RotateButton.textContent = `Повернуть: ${rotateAngle}°`;
    updateCropButton();

    InPutButton.addEventListener("click", InPutButton_Even);
    FileInput.addEventListener("change", FileInput_Even);
    SendButton.addEventListener("click", SendButton_Even);
    RotateButton.addEventListener("click", RotateButton_Even);
    CropButton.addEventListener("click", CropButton_Even);
    if (RefreshStatusButton) {
        RefreshStatusButton.addEventListener("click", function () {
            loadDeviceStatus(true);
        });
    }
    if (DeviceStatusPanel) {
        DeviceStatusPanel.addEventListener("toggle", function () {
            if (DeviceStatusPanel.open) {
                loadDeviceStatus();
            }
        });
    }

    ImageSys.onload = processCurrentImage;
}

function InPutButton_Even() {
    FileInput.click();
}

function FileInput_Even(e) {
    fileFlag = 0;
    processedBase64 = "";
    rotateAngle = 0;
    RotateButton.textContent = `Повернуть: ${rotateAngle}°`;

    const file = e.target.files[0];
    if (!file) {
        setStatus("Файл не выбран.", true);
        alert("Файл не выбран.");
        return;
    }
    if (!file.type.startsWith("image/")) {
        setStatus("Выберите файл изображения.", true);
        alert("Выберите файл изображения.");
        return;
    }

    setStatus("Загружаю, обрезаю и подготавливаю изображение...");
    const url = URL.createObjectURL(file);
    ImageSys.src = url;
    ImageSys.addEventListener('load', function revoke() {
        URL.revokeObjectURL(url);
        ImageSys.removeEventListener('load', revoke);
    });
    fileFlag = 1;
    e.target.value = '';
}

function CropButton_Even() {
    cropMode = cropMode === "cover" ? "contain" : "cover";
    updateCropButton();
    if (!fileFlag) {
        setStatus(cropMode === "cover" ? "Обрезка будет применена к следующему изображению." : "Следующее изображение будет вписано целиком.");
        return;
    }
    setStatus("Пересчитываю изображение под рамку...");
    processCurrentImage();
}

function RotateButton_Even() {
    if (!fileFlag) {
        setStatus("Сначала выберите изображение.", true);
        alert("Сначала выберите изображение.");
        return;
    }
    rotateAngle += 90;
    if (rotateAngle > 270) rotateAngle = 0;
    RotateButton.textContent = `Повернуть: ${rotateAngle}°`;
    renderProcessedPreview();
    setStatus(`Поворот предпросмотра: ${rotateAngle}°.`);
}

function createBMPUint8Array(imageData, width, height) {
    const bytesPerPixel = 3;
    const rowSize = Math.ceil((bytesPerPixel * width) / 4) * 4;
    const pixelDataSize = rowSize * height;
    const bmpFileHeaderSize = 14;
    const bmpInfoHeaderSize = 40;
    const totalBmpSize = bmpFileHeaderSize + bmpInfoHeaderSize + pixelDataSize;

    const bmpData = new Uint8Array(totalBmpSize);
    const dataView = new DataView(bmpData.buffer);

    dataView.setUint8(0, 0x42);
    dataView.setUint8(1, 0x4D);
    dataView.setUint32(2, totalBmpSize, true);
    dataView.setUint16(6, 0, true);
    dataView.setUint16(8, 0, true);
    dataView.setUint32(10, bmpFileHeaderSize + bmpInfoHeaderSize, true);

    dataView.setUint32(14, bmpInfoHeaderSize, true);
    dataView.setUint32(18, width, true);
    dataView.setUint32(22, height, true);
    dataView.setUint16(26, 1, true);
    dataView.setUint16(28, bytesPerPixel * 8, true);
    dataView.setUint32(30, 0, true);
    dataView.setUint32(34, pixelDataSize, true);
    dataView.setUint32(38, 72, true);
    dataView.setUint32(42, 72, true);
    dataView.setUint32(46, 0, true);
    dataView.setUint32(50, 0, true);

    let pixelOffset = bmpFileHeaderSize + bmpInfoHeaderSize;
    const rgba = imageData.data;

    for (let y = height - 1; y >= 0; y--) {
        let rowOffset = 0;
        for (let x = 0; x < width; x++) {
            const rgbaIndex = (y * width + x) * 4;
            bmpData[pixelOffset + rowOffset] = rgba[rgbaIndex + 2];
            bmpData[pixelOffset + rowOffset + 1] = rgba[rgbaIndex + 1];
            bmpData[pixelOffset + rowOffset + 2] = rgba[rgbaIndex];
            rowOffset += bytesPerPixel;
        }
        while (rowOffset % 4 !== 0) {
            bmpData[pixelOffset + rowOffset] = 0;
            rowOffset++;
        }
        pixelOffset += rowSize;
    }

    return bmpData;
}

function SendButton_Even() {
    if (!fileFlag) {
        setStatus("Сначала выберите изображение.", true);
        alert("Сначала выберите изображение.");
        return;
    }
    if (!processedBase64) return;

    setSendBusy(true);
    setStatus("Готовлю BMP и отправляю на рамку...");

    const modeByte = currentMode === "STA" ? 1 : 0;
    const tempCanvas = document.createElement('canvas');
    const img = new window.Image();

    img.onload = function () {
        const w = img.naturalWidth;
        const h = img.naturalHeight;
        if (rotateAngle % 180 === 0) {
            tempCanvas.width = w;
            tempCanvas.height = h;
        } else {
            tempCanvas.width = h;
            tempCanvas.height = w;
        }

        const ctx = tempCanvas.getContext('2d');
        ctx.save();
        ctx.translate(tempCanvas.width / 2, tempCanvas.height / 2);
        ctx.rotate(rotateAngle * Math.PI / 180);
        ctx.drawImage(img, -w / 2, -h / 2);
        ctx.restore();

        const imageData = ctx.getImageData(0, 0, tempCanvas.width, tempCanvas.height);
        const pureBmpData = createBMPUint8Array(imageData, tempCanvas.width, tempCanvas.height);

        const finalData = new Uint8Array(1 + pureBmpData.length);
        finalData[0] = modeByte & 0xFF;
        finalData.set(pureBmpData, 1);

        fetch("/dataUP", {
            method: "POST",
            headers: {
                "Content-Type": "application/octet-stream"
            },
            body: new Blob([finalData], { type: 'application/octet-stream' })
        })
        .then(res => {
            if (res.ok && res.status === 200) {
                return res.text().then(() => {
                    setStatus("Изображение успешно отправлено. Дождитесь полного обновления экрана, затем при необходимости откройте диагностику вручную.");
                    alert("Изображение успешно отправлено.");
                });
            }
            return res.text().then(errorMsg => {
                throw new Error(`Ошибка отправки: ${res.status})${errorMsg ? `: ${errorMsg}` : ''}`);
            }).catch(() => {
                throw new Error(`Ошибка отправки: ${res.status})`);
            });
        }).catch(err => {
            console.error("Upload error:", err);
            setStatus("Не удалось отправить изображение. Проверьте подключение к рамке.", true);
            alert("Не удалось отправить изображение.");
        }).finally(() => {
            setSendBusy(false);
        });
    };

    img.src = processedBase64;
}

function bindModeButtonEvents() {
    modeButtons.forEach(button => {
        button.addEventListener('click', function(event) {
            event.preventDefault();
            updateModeByValue(this.dataset.mode);
        });
    });
}

document.addEventListener('DOMContentLoaded', function() {
    modeButtons = document.querySelectorAll('a[data-mode]');
    tips = document.querySelectorAll('#tips > div');

    bindModeButtonEvents();
    Even_init();

    fetch('/NetWorkStatus')
        .then(response => {
            if (!response.ok) {
                throw new Error(`Request failed, status code:${response.status}`);
            }
            return response.text();
        })
        .then(data => {
            let serverMode = 'AP';
            const serverCode = parseInt(data);
            if (!isNaN(serverCode)) {
                serverMode = serverCode === 1 ? 'STA' : 'AP';
            }
            updateModeByValue(serverMode);
        })
        .catch(error => {
            console.error('Не удалось получить режим сети. Используется AP по умолчанию:', error);
            initializeMode();
        });

    if (DeviceStatusPanel && DeviceStatusPanel.open) {
        loadDeviceStatus();
        statusRefreshTimer = setInterval(loadDeviceStatus, 30000);
    }
});
